# Auto-generated by .github/workflows/release.yml on each tagged release.
# Source template: tools/homebrew/lore.cask.rb in AoJ/lore. Do not hand-edit
# in the tap — edit the template instead.
require "download_strategy"

# Custom download strategy (the built-in GitHub private-release strategy isn't
# available in cask context, and newer Homebrew scrubs token env vars during
# cask instance_eval). Reads HOMEBREW_GITHUB_API_TOKEN at *download* time and
# fetches the asset via the GitHub API asset endpoint (numeric id templated at
# release time), with the token in the URL userinfo — NOT an Authorization
# header, which Homebrew/curl would forward to the S3 redirect and break the
# download (Homebrew/brew#15244).
unless defined?(GitHubPrivateLoreDownloadStrategy)
  class GitHubPrivateLoreDownloadStrategy < CurlDownloadStrategy
    def download_url
      token = ENV["HOMEBREW_GITHUB_API_TOKEN"]
      if token.nil? || token.empty?
        raise CurlDownloadStrategyError,
              "HOMEBREW_GITHUB_API_TOKEN with read access to AoJ/lore is required"
      end
      @url.sub(%r{\Ahttps://}, "https://#{token}@")
    end

    def resolve_url_basename_time_file_size(_url, timeout: nil)
      super(download_url, timeout: timeout)
    end

    def resolved_basename
      "lore.zip"
    end

    private

    def _fetch(url:, resolved_url:, timeout:)
      curl_download download_url, "--header", "Accept: application/octet-stream", to: temporary_path
    end
  end
end

cask "lore" do
  version "@@VERSION@@"
  sha256 "@@SHA_APP@@"

  url "https://api.github.com/repos/AoJ/lore/releases/assets/@@CASK_ASSET_ID@@",
      using: GitHubPrivateLoreDownloadStrategy
  name "Lore"
  desc "Personal knowledge management desktop app"
  homepage "https://github.com/AoJ/lore"

  depends_on arch: :arm64
  depends_on macos: ">= :big_sur"

  app "Lore.app"

  caveats <<~EOS
    Set HOMEBREW_GITHUB_API_TOKEN to a token with read access to AoJ/lore
    before install/upgrade:
      export HOMEBREW_GITHUB_API_TOKEN=github_pat_...

    The app is signed with a Developer ID and notarized, so it launches without
    a Gatekeeper prompt. Database defaults to
    ~/Library/Application Support/lore/lore.db (override with LORE_DB; note a
    Dock/Finder-launched app does not inherit your shell environment).
  EOS
end
